        // Type Expressions and Match terms of the required Components, index i belongs to Ci.
        private readonly TypeExpression[] _required;
        private readonly Match[] _matches;

        private bool _disposed;
        private bool _consumed;

        internal EntityTemplate(World world, PooledList<TypeExpression> components, PooledList<object> values, TypeExpression[] required, Match[] matches)
