        }

        private EntityTemplate<C0, C1, C2, C3> AddComponent(TypeExpression type, object value)
        {
            AssertMutable();
            AssertNotRequired(type);
            if (_components.Contains(type))
            {
                // replace existing value
                _values[_components.IndexOf(type)] = value;
            }
            else
            {
                // add new value
                _components.Add(type);
                _values.Add(value);
            }
            return this;
        }

        private EntityTemplate<C0, C1, C2, C3> RemoveComponent(TypeExpression type)
        {
            AssertMutable();
            AssertNotRequired(type);
            _values.RemoveAt(_components.IndexOf(type));
            _components.Remove(type);
            return this;
        }

