        /// <returns>itself (fluent interface)</returns>
        public EntityTemplate<C0, C1, C2, C3, C4, C5> Spawn(Span<Entity> destination, ReadOnlySpan<C0> values0, ReadOnlySpan<C1> values1, ReadOnlySpan<C2> values2, ReadOnlySpan<C3> values3, ReadOnlySpan<C4> values4, ReadOnlySpan<C5> values5)
        {
            AssertMutable();
            if (values0.Length != destination.Length) throw new ArgumentException($"Length ({values0.Length}) must equal destination.Length ({destination.Length})", nameof(values0));
            if (values1.Length != destination.Length) throw new ArgumentException($"Length ({values1.Length}) must equal destination.Length ({destination.Length})", nameof(values1));
            if (values2.Length != destination.Length) throw new ArgumentException($"Length ({values2.Length}) must equal destination.Length ({destination.Length})", nameof(values2));
            if (values3.Length != destination.Length) throw new ArgumentException($"Length ({values3.Length}) must equal destination.Length ({destination.Length})", nameof(values3));
            if (values4.Length != destination.Length) throw new ArgumentException($"Length ({values4.Length}) must equal destination.Length ({destination.Length})", nameof(values4));
            if (values5.Length != destination.Length) throw new ArgumentException($"Length ({values5.Length}) must equal destination.Length ({destination.Length})", nameof(values5));
            if (destination.IsEmpty) return this;

            // Broadcast-spawn the wave (lands contiguously, in destination order, per aspect
            // archetype), then blit each value span straight into its storage slice. (no boxing)
            Spawn(destination, values0[0], values1[0], values2[0], values3[0], values4[0], values5[0]);
            var slice0 = _world.ContiguousSlice<C0>(destination[0], _matches[0], destination.Length);
            Debug.Assert(Unsafe.AreSame(ref slice0[^1], ref destination[^1].Ref<C0>(_matches[0])), "Spawn wave is not contiguous in Component storage.");
            values0.CopyTo(slice0);
            var slice1 = _world.ContiguousSlice<C1>(destination[0], _matches[1], destination.Length);
            Debug.Assert(Unsafe.AreSame(ref slice1[^1], ref destination[^1].Ref<C1>(_matches[1])), "Spawn wave is not contiguous in Component storage.");
            values1.CopyTo(slice1);
            var slice2 = _world.ContiguousSlice<C2>(destination[0], _matches[2], destination.Length);
            Debug.Assert(Unsafe.AreSame(ref slice2[^1], ref destination[^1].Ref<C2>(_matches[2])), "Spawn wave is not contiguous in Component storage.");
            values2.CopyTo(slice2);
            var slice3 = _world.ContiguousSlice<C3>(destination[0], _matches[3], destination.Length);
            Debug.Assert(Unsafe.AreSame(ref slice3[^1], ref destination[^1].Ref<C3>(_matches[3])), "Spawn wave is not contiguous in Component storage.");
            values3.CopyTo(slice3);
            var slice4 = _world.ContiguousSlice<C4>(destination[0], _matches[4], destination.Length);
            Debug.Assert(Unsafe.AreSame(ref slice4[^1], ref destination[^1].Ref<C4>(_matches[4])), "Spawn wave is not contiguous in Component storage.");
            values4.CopyTo(slice4);
            var slice5 = _world.ContiguousSlice<C5>(destination[0], _matches[5], destination.Length);
            Debug.Assert(Unsafe.AreSame(ref slice5[^1], ref destination[^1].Ref<C5>(_matches[5])), "Spawn wave is not contiguous in Component storage.");
            values5.CopyTo(slice5);
            return this;
        }

        /// <summary>
        /// Spawns <c>count</c> Entities with the configured Components, calling <paramref name="factory"/>
        /// with each Entity's index to produce its required values.
        /// </summary>
        /// <param name="count">number of Entities to spawn</param>
        /// <param name="factory">produces the required values for the Entity at each index</param>
        /// <returns>itself (fluent interface)</returns>
        public EntityTemplate<C0, C1, C2, C3, C4, C5> Spawn(int count, Func<int, (C0, C1, C2, C3, C4, C5)> factory)
        {
            AssertMutable();
            ArgumentNullException.ThrowIfNull(factory);
            if (count <= 0) return this;

            var entities = ArrayPool<Entity>.Shared.Rent(count);
            Spawn(entities.AsSpan(0, count), factory);
            ArrayPool<Entity>.Shared.Return(entities);
            return this;
        }

        /// <summary>
        /// Spawns one Entity per element of <paramref name="destination"/>, calling <paramref name="factory"/>
        /// with each Entity's index to produce its required values, and writing the minted handles
        /// into <paramref name="destination"/>.
        /// </summary>
        /// <param name="destination">span to fill; its length determines the number of Entities spawned</param>
        /// <param name="factory">produces the required values for the Entity at each index</param>
        /// <returns>itself (fluent interface)</returns>
        public EntityTemplate<C0, C1, C2, C3, C4, C5> Spawn(Span<Entity> destination, Func<int, (C0, C1, C2, C3, C4, C5)> factory)
        {
            AssertMutable();
            ArgumentNullException.ThrowIfNull(factory);
            if (destination.IsEmpty) return this;

            var count = destination.Length;
            var rented0 = ArrayPool<C0>.Shared.Rent(count);
            var rented1 = ArrayPool<C1>.Shared.Rent(count);
            var rented2 = ArrayPool<C2>.Shared.Rent(count);
            var rented3 = ArrayPool<C3>.Shared.Rent(count);
            var rented4 = ArrayPool<C4>.Shared.Rent(count);
            var rented5 = ArrayPool<C5>.Shared.Rent(count);
            for (var i = 0; i < count; i++)
            {
                var (c0, c1, c2, c3, c4, c5) = factory(i);
                rented0[i] = c0;
                rented1[i] = c1;
                rented2[i] = c2;
                rented3[i] = c3;
                rented4[i] = c4;
                rented5[i] = c5;
            }
            Spawn(destination, rented0.AsSpan(0, count), rented1.AsSpan(0, count), rented2.AsSpan(0, count), rented3.AsSpan(0, count), rented4.AsSpan(0, count), rented5.AsSpan(0, count));
            ArrayPool<C0>.Shared.Return(rented0, RuntimeHelpers.IsReferenceOrContainsReferences<C0>());
            ArrayPool<C1>.Shared.Return(rented1, RuntimeHelpers.IsReferenceOrContainsReferences<C1>());
            ArrayPool<C2>.Shared.Return(rented2, RuntimeHelpers.IsReferenceOrContainsReferences<C2>());
            ArrayPool<C3>.Shared.Return(rented3, RuntimeHelpers.IsReferenceOrContainsReferences<C3>());
            ArrayPool<C4>.Shared.Return(rented4, RuntimeHelpers.IsReferenceOrContainsReferences<C4>());
            ArrayPool<C5>.Shared.Return(rented5, RuntimeHelpers.IsReferenceOrContainsReferences<C5>());
            return this;
        }

        /// <inheritdoc />
        public void Dispose()
        {
            ObjectDisposedException.ThrowIf(_disposed, this);
            _disposed = true;

            _components.Dispose();
            _components = null!;

            _values.Dispose();
            _values = null!;
        }
    }

